python3 -c "import json,sys,subprocess
try:
    d=json.load(sys.stdin)
except Exception:
    sys.exit(0)
fp=d.get('file_path','')
if fp.endswith('.ts'):
    r=subprocess.run(['npm','run','lint'],capture_output=True,text=True)
    out=(r.stdout+r.stderr).strip()
    if out:
        lines=out.split('\n')
        print('\n'.join(lines[-8:]))
    else:
        print('Lint failed with no output')
    sys.exit(r.returncode)"

